1	const fs = require('fs');
2	const path = require('path');
3	
4	const s1 = JSON.parse(fs.readFileSync(path.join(__dirname, '..', 'data', 's1_classification.json'), 'utf8'));
5	const chatDir = path.join(__dirname, '..', 'data', 'chat_history');
6	const NOW = Date.now();
7	const DAY = 86400000;
8	const OUR_UID = '2500000853693@icbu';
9	
10	// ── 工具函数 ──
11	const SYS_PATTERNS = [
12	  '自动接待将不再触发', 'Since you have read the conversation',
13	  'Marco大模型翻译', '阿里国际Marco大模型翻译',
14	  '有流失', 'Buyer has churn risk',
15	  '一旦离开平台', '由于您介入该会话', 'Due to your intervention',
16	  '平台规则提醒', '查看规则', '平台交易有保障', '平台已告知买家',
17	  'AI智能判断该买家', '该买家已去除', '享受安全保障',
18	  '翻译结果由买家发送', '由阿里翻译提供',
19	  '买家进店', '访客接待',
20	  '撤回了一条消息',
21	  '反馈', 'AI给您生成了一条回复建议', 'AI给您生成',
22	  'You have a visitor', 'This buyer has been pre-screened',
23	  '当前买家首次给您发消息', '查看买家特征',
24	];
25	function isSys(c) { const t = c && c.text && c.text.content || ''; if (c && c.custom) return false; if (!t.trim()) return true; for (const p of SYS_PATTERNS) if (t.includes(p)) return true; return false; }
26	function getText(c, sc) { if (c && c.text && c.text.content) return c.text.content; if (c && c.custom) { if (sc && sc.summary) return sc.summary; return '[产品卡片]'; } return ''; }
27	
28	const Q_PATTERNS = [/\?/, /(what|how|when|where|which|who|why|whom)/i, /(can you|could you|would you|will you|do you|is it|are you)/i, /(please.*(send|give|tell|quote|share|confirm|advise|provide|let me know))/i, /(i need|i want|i would like|i'm looking for|we need|we want|we are looking)/i, /[吗呢吧啊]/, /[？]/, /(价格|报价|多少钱|什么价)/, /(样品|sample|打样)/i, /(MOQ|起订量|最小.*量)/i, /(交期|delivery.*time|lead.*time)/i];
29	function isQuestion(text) { if (!text || text.length < 3) return false; for (const p of Q_PATTERNS) if (p.test(text)) return true; return false; }
30	
31	function assessQuality(qText, rText) {
32	  if (!rText || rText.trim().length === 0) return { q: '未回复', s: 0 };
33	  const len = rText.trim().length;
34	  if (/^(ok|okay|yes|no|thanks|thank you|got it|noted|well|sure|好的|收到|嗯|哦|知道了)[\s,.]*$/i.test(rText.trim()) || len < 15) return { q: '敷衍回复', s: 1 };
35	  if (len < 50) return { q: '简短回复', s: 2 };
36	  const qw = (qText || '').toLowerCase().replace(/[?？,.]/g, '').split(/\s+/).filter(w => w.length > 3);
37	  const rl = rText.toLowerCase();
38	  const m = qw.filter(w => rl.includes(w));
39	  return (m.length / Math.max(qw.length, 1) >= 0.3 || len >= 100) ? { q: '充分回复', s: 3 } : { q: '简短回复', s: 2 };
40	}
41	
42	// ── 生命周期判定 ──
43	function determineLifecycle(e) {
44	  const { hasPI, hasAddress, hasOrderSignal, hasPrice, hasSample, hasQuantity, realMsgs, customerMsgs, ourMsgs, daysAgo, lastCustomerMsgDays, questionUnanswered, lastCustQuestion } = e;
45	  const fullText = ((e.latestOurMsg || '') + ' ' + (e.latestCustMsg || '') + ' ' + (e.lastCustQuestion || '')).toLowerCase();
46	
47	  // 订单执行中：付款确认+生产/发货讨论
48	  if (hasPI && /(paid|payment.*done|deposit.*paid|生产|produc|ship.*out|on the way|tracking|dispatch)/i.test(fullText)) return { stage: 6, label: '订单执行中', icon: '📦' };
49	
50	  // 已签收
51	  if (hasPI && /(received|arrived|delivered|got.*goods|收到.*货|签收)/i.test(fullText)) return { stage: 7, label: '已签收', icon: '✅' };
52	
53	  // PI已发（不限天数，只看信号）
54	  if (hasPI) return { stage: 5, label: 'PI已发', icon: '📄' };
55	
56	  // 售后疑似标记：关键词命中只打标，不硬判。需人工/AI读对话确认
57	  const custText = ((e.latestCustMsg || '') + ' ' + (e.lastCustQuestion || '')).toLowerCase();
58	  e.afterSalesFlag = false;
59	  const afterSalesRe = /(damage|broken|defect|complain|refund|bad quality|poor quality|not satisfied|not happy|send back|exchange|replace|有问题|坏的|退货|退款|投诉|质量差|不满意|换货|搞错了|发错了)/i;
60	  if (realMsgs >= 3 && customerMsgs >= 1 && afterSalesRe.test(custText)) {
61	    e.afterSalesFlag = true;
62	  }
63	
64	  // 谈判/样品（不限天数）
65	  if ((hasPrice || hasSample) && hasQuantity && realMsgs >= 10) return { stage: 4, label: '谈判/样品', icon: '🤝' };
66	  if (hasSample && realMsgs >= 5) return { stage: 4, label: '谈判/样品', icon: '🤝' };
67	
68	  // 报价已发（不限天数）
69	  if (hasPrice) return { stage: 3, label: '报价已发', icon: '💰' };
70	
71	  // 待回复：客户有新消息未回
72	  if (questionUnanswered || (customerMsgs > ourMsgs && lastCustomerMsgDays <= 1)) return { stage: 1, label: '待回复', icon: '🔴' };
73	
74	  // 初询沟通（不限天数）
75	  if (realMsgs >= 1) return { stage: 2, label: '初询沟通', icon: '📋' };
76	
77	  return { stage: 0, label: '待分类', icon: '❓' };
78	}
79	
80	// ── 沉默副状态 ──
81	function silenceLabel(days) {
82	  if (days >= 90) return '沉淀(90d+)';
83	  if (days >= 30) return '深度沉默(30-90d)';
84	  if (days >= 14) return '长期沉默(14-30d)';
85	  if (days >= 7) return '中期沉默(7-14d)';
86	  if (days >= 3) return '短期沉默(3-7d)';
87	  return '';
88	}
89	
90	// ── 质量等级判定 ──
91	function determineQuality(e, fullCustText, fullConvText) {
92	  const ft = (fullConvText || '').toLowerCase();
93	  const ct = (fullCustText || '').toLowerCase();
94	
95	  // ── 全量对话提取数量信息（从客户消息提取更可靠）──
96	  // 支持英/中/法/西/阿语常见数量单位
97	  const qtyMatches = ct.match(/(\d{3,})\s*(pcs|pieces|units?|unit[ée]s?|件|piece|pc|pce|paires?|douzaines?|qt[ée]|quantit[ée]s?|sets?|ensembles?)/gi) || [];
98	  let maxQty = 0;
99	  for (const qm of qtyMatches) {
100	    const n = parseInt(qm.match(/\d+/)[0], 10);
101	    if (n > maxQty) maxQty = n;
102	  }
103	
104	  // ── 母婴品类信号（修正 D 误判用）──
105	  const isBabyRelated = /(baby|kid|child|infant|toddler|newborn|bib|romper|bodysuit|onesie|swaddle|sleepsuit|blanket|crib|stroller|nursery|童|婴|幼|卡通|cartoon)/i.test(ft);
106	
107	  // ── S 级信号（严格版 — 优先用 ct 即客户消息）──
108	  const sSignals = [];
109	  // 品牌/ODM: 明确且有意图的组合（含法/西/阿语）
110	  if (/(odm|oem|private\s*(label|brand)|own\s*(brand|design|label)|custom\s*(logo|packaging|packing|design|label|box|bag|tag)|hangtag|barcode|brand\s*name|brand\s*label|your\s*logo|my\s*logo|our\s*logo|marque|personnalis[ée]|personnaliser|[ée]tiquette.*perso|logo.*perso|votre.*logo|mon.*logo|mon.*design|mon.*propre)/i.test(ct))
111	    sSignals.push('品牌/ODM');
112	  // 分销渠道: 明确平台或分销语言（含法/西/阿语）
113	  if (/(amazon|walmart|shopify|distributor|retail\s*(chain|store|shop)|wholesale\s*(channel|distributor|business)|sell\s*(on|through|in)\s*(amazon|walmart|shopify|online)|revendeur|distributeur|vendre.*(sur|en ligne|amazon)|boutique.*(en ligne|online)|tienda.*(online|en.linea)|mayorista)/i.test(ct))
114	    sSignals.push('分销渠道');
115	  if (maxQty >= 500) sSignals.push('大批量(' + maxQty + '件)');
116	  // 公司资料: 客户主动分享
117	  if (/(here.*(is|are).*(website|store|shop|link)|check.*(my|our).*(website|store|shop|page)|this\s*is\s*(my|our).*(website|store|shop)|find\s*(us|me).*(on|at).*(website|store))/i.test(ct) ||
118	      /(https?:\/\/|www\.\w+\.(com|net|org|co))/i.test(ct))
119	    sSignals.push('公司资料');
120	  // 复购: 明确的复购/追加语言
121	  if (/(reorder|restock|another\s*(order|shipment|batch|container)|second\s*(order|shipment)|repeat\s*order|buy\s*more|order\s*more|send\s*more|top\s*up)/i.test(ct))
122	    sSignals.push('复购信号');
123	
124	  // ── A 级附加信号 ──
125	  const aSignals = [];
126	  if (maxQty >= 200 && maxQty < 500) aSignals.push('中批量(' + maxQty + '件)');
127	  if (/(500.*ok|500.*fine|moq.*(ok|fine|accept|no.*problem)|accept.*(moq|500|minimum)|can.*(take|do|handle).*500|ok.*(with|about).*(500|moq)|no.*problem.*(500|moq)|(je|nous).*(prends?|commande|veux|voudrais).*500|500.*(va|marche|ok|d'accord)|pas.*probl[èe]me.*500)/i.test(ct))
128	    aSignals.push('MOQ已接受');
129	  if (/(sample.*(sent|shipped|sending|ready|prepar|made|done|making|proceed)|(sent|shipped|send|ready).*sample|样品.*(寄|发|做|准备))/i.test(ft))
130	    aSignals.push('样品已寄/在准备');
131	  if (e.realMsgs >= 15 && e.customerMsgs >= 3)
132	    aSignals.push('深度沟通(' + e.realMsgs + '条)');
133	  if (/(price.*(high|expensive|too much|negot|discount|lower|reduce|better.*price|best.*price|last.*price|final.*price)|便宜|贵|折扣|降价|便宜点|r[ée]duction|remise|rabais|n[ée]goci|trop.*(cher|[ée]lev[ée]|haut)|moins.*cher|prix.*(bas|moins)|descuento|rebaja|caro|muy.*caro|barato)/i.test(ct))
134	    aSignals.push('价格谈判');
135	  if (/(bsci|iso|audit|certif|认证|factory.*(video|tour|visit)|验厂|验货)/i.test(ct))
136	    aSignals.push('关心认证/验厂');
137	  if (/(freight|shipping|运费|物流|delivery.*cost|ship.*cost|transport.*cost|dhl|fedex|ups|aramex|courier|by sea|by air|container)/i.test(ct) && e.hasQuantity)
138	    aSignals.push('讨论运费+数量');
139	
140	  // ── C 级降级信号 ──
141	  const cSignals = [];
142	  if (/(for myself|for my kid|for my baby|personal use|自用|送人|gift.*for|for.*gift|personal.*purchase|own.*use|just.*for.*(me|myself|my.*kid|my.*baby)|pour moi|pour mon|personnel|usage.*personnel|uso.*personal|para mi)/i.test(ct))
143	    cSignals.push('个人自用');
144	  if (/(just.*(few|a few|small|little|some)|small.*(quantity|order|business|little)|little.*(order|quantity|business|bit)|tiny|only.*(need|want).*\d{1,2}\s*(pcs|pieces)|petit.*(quantit[ée]|commande)|peu.*(de|commande)|juste.*(quelques|un peu)|solo.*(pocos?|pocas?|unos?|unas?))/i.test(ct))
145	    cSignals.push('小批量暗示');
146	  if (maxQty > 0 && maxQty <= 50) cSignals.push('明确小量(' + maxQty + '件)');
147	  if (e.realMsgs <= 3 && e.customerMsgs === 1 && !e.hasPrice && !e.hasSample && !e.hasQuantity)
148	    cSignals.push('单次浅层互动');
149	
150	  // ── D 级判定（修正版）──
151	  if (e.realMsgs <= 2 && e.customerMsgs === 0)
152	    return { grade: 'D', label: '无关/废弃', reason: '仅系统消息/无真实对话', auto: true };
153	
154	  // 品类不匹配：成人/非母婴 AND NOT 母婴相关
155	  if (/(adult|成人|men.*wear|男装|sexy|lingerie|women.*dress|fashion.*(dress|wear)|wedding|evening.*(dress|wear)|not.*(baby|kid|child))/i.test(ft) && !isBabyRelated)
156	    return { grade: 'D', label: '无关', reason: '品类不匹配(非母婴)', auto: true };
157	
158	  // 非采购意图
159	  if (/(转让|加盟|franchise|找.*工作|job|hiring|recruit|sell.*business)/i.test(ft) && e.realMsgs <= 5)
160	    return { grade: 'D', label: '无关', reason: '非采购意图', auto: true };
161	
162	  // ── 综合定级 ──
163	  const totalSSignals = sSignals.length;
164	  const totalASignals = aSignals.length;
165	  const totalCSignals = cSignals.length;
166	
167	  // S: 2+ 个S级信号
168	  if (totalSSignals >= 2)
169	    return { grade: 'S', label: '战略客户', reason: sSignals.join('+'), auto: true };
170	
171	  // A: 1个S级信号 或 (2+个A级信号+有实质互动)
172	  if (totalSSignals >= 1)
173	    return { grade: 'A', label: '优质客户', reason: [...sSignals, ...aSignals].filter(Boolean).join('+') || sSignals.join('+'), auto: true };
174	
175	  if (totalASignals >= 2 && e.realMsgs >= 5)
176	    return { grade: 'A', label: '优质客户', reason: aSignals.join('+'), auto: true };
177	
178	  // C: 明确降级信号 + 无上升信号
179	  if (totalCSignals >= 2 && totalSSignals === 0 && totalASignals <= 1)
180	    return { grade: 'C', label: '低价值', reason: cSignals.join('+'), auto: true };
181	
182	  if (maxQty > 0 && maxQty <= 30 && totalSSignals === 0 && totalASignals === 0)
183	    return { grade: 'C', label: '低价值', reason: '明确小量≤30件', auto: true };
184	
185	  // 单次互动无后续 → C（而非B）
186	  if (e.realMsgs <= 4 && e.customerMsgs >= 1 && e.customerMsgs <= 2 && !e.hasPrice && !e.hasSample && !e.hasQuantity && typeof e.lastCustomerMsgDays === 'number' && e.lastCustomerMsgDays > 30)
187	    return { grade: 'C', label: '低价值', reason: '单次互动+30天无后续', auto: true };
188	
189	  // 浅互动+长期沉默 → C（"问完消失"模式）
190	  if (e.realMsgs <= 5 && e.customerMsgs <= 2 && totalSSignals === 0 && totalASignals <= 1 && typeof e.lastCustomerMsgDays === 'number' && e.lastCustomerMsgDays > 60)
191	    return { grade: 'C', label: '低价值', reason: '浅互动+长期沉默(' + e.lastCustomerMsgDays + 'd)', auto: true };
192	
193	  // B: 有实质互动，信号不足以升A/S也不足以降C/D
194	  if (e.realMsgs >= 3 && e.customerMsgs >= 1)
195	    return { grade: 'B', label: '普通客户', reason: '有互动但信号不足', auto: true };
196	
197	  if (e.hasPrice || e.hasSample || e.hasQuantity)
198	    return { grade: 'B', label: '普通客户', reason: '有实质讨论', auto: true };
199	
200	  return { grade: 'B', label: '普通客户', reason: '信息不足', auto: true };
201	}
