203	// ── 国家代码→中文映射 ──
204	const COUNTRY_CN = {
205	  'US':'美国','GB':'英国','DE':'德国','FR':'法国','IT':'意大利','ES':'西班牙','NL':'荷兰','BE':'比利时','PT':'葡萄牙','RU':'俄罗斯','TR':'土耳其',
206	  'IN':'印度','PK':'巴基斯坦','BD':'孟加拉','JP':'日本','KR':'韩国','HK':'香港','ID':'印尼','MY':'马来西亚','PH':'菲律宾','VN':'越南','TH':'泰国',
207	  'SD':'苏丹','EG':'埃及','CD':'刚果民主','ZM':'赞比亚','CI':'科特迪瓦','SA':'沙特','AE':'阿联酋','GH':'加纳','NG':'尼日利亚','KE':'肯尼亚','TZ':'坦桑尼亚',
208	  'ZA':'南非','MA':'摩洛哥','DZ':'阿尔及利亚','TN':'突尼斯','LY':'利比亚','ET':'埃塞俄比亚','UG':'乌干达','RW':'卢旺达','CM':'喀麦隆','SN':'塞内加尔',
209	  'ML':'马里','TG':'多哥','BJ':'贝宁','BF':'布基纳法索','CG':'刚果','GA':'加蓬','ZR':'刚果(金)','LR':'利比里亚','SL':'塞拉利昂','GN':'几内亚',
210	  'IQ':'伊拉克','LB':'黎巴嫩','JO':'约旦','KW':'科威特','QA':'卡塔尔','OM':'阿曼','BH':'巴林','IL':'以色列','SY':'叙利亚','YE':'也门',
211	  'BR':'巴西','AR':'阿根廷','CL':'智利','CO':'哥伦比亚','PE':'秘鲁','MX':'墨西哥','BO':'玻利维亚','VE':'委内瑞拉','EC':'厄瓜多尔','PY':'巴拉圭',
212	  'AU':'澳大利亚','NZ':'新西兰','CA':'加拿大','PL':'波兰','UA':'乌克兰','RO':'罗马尼亚','HU':'匈牙利','CZ':'捷克','SE':'瑞典','DK':'丹麦',
213	  'MD':'摩尔多瓦','PA':'巴拿马','ZW':'津巴布韦','DJ':'吉布提',
214	};
215	function countryCN(code) { return COUNTRY_CN[code] || code; }
216	
217	// ── 行动引擎 ──
218	// 返回 { status: "当前状态描述", action: "行动方向", priority: "urgent|soon|watch|idle" }
219	function getAction(e) {
220	  const d = typeof e.lastCustomerMsgDays === 'number' ? e.lastCustomerMsgDays : 9999;
221	  const g = e.grade;
222	  const stage = e.stageLabel;
223	
224	  if (stage === '待回复') {
225	    return { status: '客户消息待回复', action: '24h内回复（平台考核及时回复率）', priority: 'urgent' };
226	  }
227	
228	  if (stage === '售后') {
229	    const act = (g === 'S' || g === 'A') ? '≤1h响应，主动给补偿方案' : '24h内回复，标准处理流程';
230	    return { status: '售后/投诉处理中', action: act, priority: 'urgent' };
231	  }
232	
233	  if (stage === '订单执行中') {
234	    if (d <= 7) return { status: '订单进行中，上次互动' + d + '天前', action: (g === 'S' || g === 'A') ? '每周同步进度，拍照/视频' : '关键节点通知（排产/发货）', priority: 'watch' };
235	    return { status: '订单进行中，已' + d + '天未同步', action: '主动同步生产进度+发货时间', priority: 'soon' };
236	  }
237	
238	  if (stage === '已签收') {
239	    if (d <= 1) return { status: '刚签收', action: '当天回访：确认收货完好+问反馈', priority: 'urgent' };
240	    if (d <= 3) return { status: '签收' + d + '天', action: '3天回访：问产品质量+使用情况', priority: 'soon' };
241	    if (d <= 7) return { status: '签收' + d + '天', action: '7天回访：发新品目录+争取复购', priority: 'soon' };
242	    if (d <= 30) return { status: '签收' + d + '天', action: '确认满意度+发新品，推动复购', priority: 'watch' };
243	    return { status: '签收' + d + '天，进入复购周期', action: (g === 'S' || g === 'A') ? '定期同步新品+定制方案' : '节日/新品节点触达', priority: 'idle' };
244	  }
245	
246	  if (stage === 'PI已发') {
247	    // PI已发有独立节奏（不等同于前面快节奏阶段）
248	    if (d <= 2) return { status: 'PI刚发' + d + '天，确认期', action: (g === 'S' || g === 'A') ? '48h内确认客户收到PI' : '确认PI已收到', priority: 'urgent' };
