content.text:
以下是完整报告。

---

## 1. `determineLifecycle()` 完整代码（第43-78行）

```js
function determineLifecycle(e) {
  const { hasPI, hasAddress, hasOrderSignal, hasPrice, hasSample, hasQuantity, realMsgs, customerMsgs, ourMsgs, daysAgo, lastCustomerMsgDays, questionUnanswered, lastCustQuestion } = e;
  const fullText = ((e.latestOurMsg || '') + ' ' + (e.latestCustMsg || '') + ' ' + (e.lastCustQuestion || '')).toLowerCase();

  // 订单执行中：付款确认+生产/发货讨论
  if (hasPI && /(paid|payment.*done|deposit.*paid|生产|produc|ship.*out|on the way|tracking|dispatch)/i.test(fullText)) return { stage: 6, label: '订单执行中', icon: '📦' };

  // 已签收
  if (hasPI && /(received|arrived|delivered|got.*goods|收到.*货|签收)/i.test(fullText)) return { stage: 7, label: '已签收', icon: '✅' };

  // PI已发（不限天数，只看信号）
  if (hasPI) return { stage: 5, label: 'PI已发', icon: '📄' };

  // 售后疑似标记：关键词命中只打标，不硬判。需人工/AI读对话确认
  const custText = ((e.latestCustMsg || '') + ' ' + (e.lastCustQuestion || '')).toLowerCase();
  e.afterSalesFlag = false;
  const afterSalesRe = /(damage|broken|defect|complain|refund|bad quality|poor quality|not satisfied|not happy|send back|exchange|replace|有问题|坏的|退货|退款|投诉|质量差|不满意|换货|搞错了|发错了)/i;
  if (realMsgs >= 3 && customerMsgs >= 1 && afterSalesRe.test(custText)) {
    e.afterSalesFlag = true;
  }

  // 谈判/样品（不限天数）
  if ((hasPrice || hasSample) && hasQuantity && realMsgs >= 10) return { stage: 4, label: '谈判/样品', icon: '🤝' };
  if (hasSample && realMsgs >= 5) return { stage: 4, label: '谈判/样品', icon: '🤝' };

  // 报价已发（不限天数）
  if (hasPrice) return { stage: 3, label: '报价已发', icon: '💰' };

  // 待回复：客户有新消息未回
  if (questionUnanswered || (customerMsgs > ourMsgs && lastCustomerMsgDays <= 1)) return { stage: 1, label: '待回复', icon: '🔴' };

  // 初询沟通（不限天数）
  if (realMsgs >= 1) return { stage: 2, label: '初询沟通', icon: '📋' };

  return { stage: 0, label: '待分类', icon: '❓' };
}
```

**逻辑概要**：该函数根据客户会话中的信号按优先级依次判断 —— 它使用严格的"先返回"链，先匹配高阶段（订单执行中 > 已签收 > PI已发），然后是谈判/样品 > 报价已发 > 待回复 > 初询沟通 > 待分类。售后仅打标志（`e.afterSalesFlag`），不以独立生命周期阶段硬判。判断完全基于对话文本的正则匹配（正则中用 `i` 标志做不区分大小写匹配），**从不使用后端订单数据**。

---

## 2. `getAction()` 完整代码（第219-276行）

```js
function getAction(e) {
  const d = typeof e.lastCustomerMsgDays === 'number' ? e.lastCustomerMsgDays : 9999;
  const g = e.grade;
  const stage = e.stageLabel;

  if (stage === '待回复') {
    return { status: '客户消息待回复', action: '24h内回复（平台考核及时回复率）', priority: 'urgent' };
  }

  if (stage === '售后') {
    const act = (g === 'S' || g === 'A') ? '≤1h响应，主动给补偿方案' : '24h内回复，标准处理流程';
    return { status: '售后/投诉处理中', action: act, priority: 'urgent' };
  }

  if (stage === '订单执行中') {
    if (d <= 7) return { status: '订单进行中，上次互动' + d + '天前', action: (g === 'S' || g === 'A') ? '每周同步进度，拍照/视频' : '关键节点通知（排产/发货）', priority: 'watch' };
    return { status: '订单进行中，已' + d + '天未同步', action: '主动同步生产进度+发货时间', priority: 'soon' };
  }

  if (stage === '已签收') {
    if (d <= 1) return { status: '刚签收', action: '当天回访：确认收货完好+问反馈', priority: 'urgent' };
    if (d <= 3) return { status: '签收' + d + '天', action: '3天回访：问产品质量+使用情况', priority: 'soon' };
    if (d <= 7) return { status: '签收' + d + '天', action: '7天回访：发新品目录+争取复购', priority: 'soon' };
    if (d <= 30) return { status: '签收' + d + '天', action: '确认满意度+发新品，推动复购', priority: 'watch' };
    return { status: '签收' + d + '天，进入复购周期', action: (g === 'S' || g === 'A') ? '定期同步新品+定制方案' : '节日/新品节点触达', priority: 'idle' };
  }

  if (stage === 'PI已发') {
    if (d <= 2) return { status: 'PI刚发' + d + '天，确认期', action: (g === 'S' || g === 'A') ? '48h内确认客户收到PI' : '确认PI已收到', priority: 'urgent' };
    if (d <= 5) return { status: 'PI已发' + d + '天，首次提醒窗口', action: (g === 'S' || g === 'A') ? '提醒付款，附排产计划增加紧迫感' : '温和提醒PI到期时间', priority: 'soon' };
    if (d <= 14) return { status: 'PI已发' + d + '天，催款窗口', action: (g === 'S' || g === 'A') ? '催款+问"是否需要调整PI"' : '确认是否继续+问是否有障碍', priority: 'soon' };
    if (d <= 30) return { status: 'PI已发' + d + '天，需重新激活', action: (g === 'S' || g === 'A') ? '问"还在进行吗"+给替代方案/新选项' : '温和问"需要我重新报吗"', priority: 'idle' };
    return { status: 'PI已发' + d + '天，长期未转化', action: (g === 'S' || g === 'A') ? '保持1-2月/次最低触达' : '降频触达，等新产品激活', priority: 'idle' };
  }

  // 初询沟通 / 报价已发 / 谈判样品 / 未分类 — 统一快节奏
  const stageName = stage === '初询沟通' ? '初询' : stage === '报价已发' ? '报价后' : stage === '谈判/样品' ? '谈判中' : stage;
  if (d <= 1) {
    return { status: stageName + '，昨日互动', action: (g === 'S' || g === 'A') ? '今日跟进，带新信息推进' : '今日跟进，保持对话节奏', priority: 'urgent' };
  }
  if (d <= 3) {
    return { status: stageName + '，沉默' + d + '天', action: (g === 'S' || g === 'A') ? '追问需求+发认证/案例增加信任' : '换切入点追问，保持存在感', priority: 'soon' };
  }
  if (d <= 5) {
    return { status: stageName + '，沉默' + d + '天', action: (g === 'S' || g === 'A') ? '发新品/同行案例，换个角度推进' : '温和提醒+问是否有新需求', priority: 'soon' };
  }
  if (d <= 7) {
    return { status: stageName + '，沉默' + d + '天', action: (g === 'S' || g === 'A') ? '定制激活：复盘卡点+针对性破局' : '发工厂动态/新品+问"还在找吗"', priority: 'soon' };
  }
  if (d <= 14) {
    return { status: stageName + '，沉默' + d + '天，需激活', action: (g === 'S' || g === 'A') ? '发认证更新+同行案例+问"上次方向还继续吗"' : '发新品类/新到货，重新建立联系', priority: 'watch' };
  }
  if (d <= 30) {
    return { status: stageName + '，长期沉默' + d + '天', action: (g === 'S' || g === 'A') ? '不催单。发工厂动态/节日/认证维存在感' : '降频15天/次，等新产品激活', priority: 'watch' };
  }
  return { status: stageName + '，沉淀' + d + '天', action: (g === 'S' || g === 'A') ? '保持1-2月最低触达' : '暂停触达，等新产品/新认证再激活', priority: 'idle' };
}
```

**逻辑概要**：该函数接收生命周期阶段 + 质量等级 + 客户静默天数，输出带有优先级的状态描述和行动建议。典型的决策路径是：特殊阶段（待回复/售后/订单执行中/已签收/PI已发）有各自专属的沉默天数分桶逻辑；其他阶段（初询沟通/报价已发/谈判/样品/待分类）归入统一的快节奏决策路径，仅根据 S/A vs B/C/D 区分 S/A 级客户获得更主动、定制化的行动建议。

---

## 3. 脚本输入/输出流程

### 输入

脚本在顶部加载两个数据源：

**（A）`data/s1_classification.json`** -- 由 `scripts/sync_okki.js` 生成。这是通过 CDP/Chrome 调试协议从 OKKI CRM Web 界面抓取的原始客户列表。结构中包含嵌套的 `results` 对象，键为 `"0"` 到 `"4"`（对应旧 P0-P4 优先级层级），每个键对应一个客户对象数组。客户对象包含字段：`name`、`country`、`daysAgo`、`isUnread`、`cid`（在 OKKI 内用于定位实际消息的联系人ID）、`latestContent`、`companyName` 等。

**（B）`data/chat_history/`**（单个 `cid.json` 文件目录）-- 每个文件包含特定客户会话的完整消息历史。该目录由 `sync_okki.js` 填充。每条消息包含：`sender.uid`、`content`（可能是带有 `content.text.content` 的文本对象，也可能是带有 `content.custom` 的产品卡片）、`createAt`（Unix 时间戳）、`searchableContent`。

### 处理过程

对于 `s1_classification.json` 中的每位客户：
1. 从 `data/chat_history/{filename}` 加载聊天记录
2. 对消息进行标记（对方/我方/系统），提取所有信号标志（`hasPI`、`hasPrice`、`hasSample` 等）
3. 找到客户的上一条提问和带有质量评分及延迟信息的我方回复
4. `determineLifecycle(obj)` -- 提供生命周期阶段（0-7 阶段，从待分类到已签收）
5. `determineQuality(obj, fullCustText, fullConvText)` -- 提供质量等级（S/A/B/C/D），通过扫描全量客户消息以匹配多语言信号，并有针对婴儿品类误判的保护
6. 附加静默状态等级（3-7天 / 7-14天 / 14-30天 / 30-90天 / 90天以上）
7. `getAction(obj)` -- 提供优先级 + 可操作的状态 + 行动描述
8. 按紧急程度排序（待回复最优先，然后是 PI已发 > 谈判/样品 > 报价已发 > 初询沟通 > 订单执行中 > 已签收 > 售后 > 待分类）

### 输出

该脚本生成三件产物：

**（A）`data/s1_enhanced.json`**（主结构化输出）-- 每位客户一个包含以下字段的对象数组：
- 身份信息：`name`, `country`, `countryCN`, `cid`, `daysAgo`
- 消息统计：`msgCount`, `customerMsgs`, `ourMsgs`, `realMsgs`, `lastCustomerMsgDays`
- 信号标志：`hasPI`, `hasPrice`, `hasSample`, `hasQuantity` 等
- 生命周期：`stage`（0-7 整数）、`stageLabel`、`stageIcon`
- 质量：`grade`（S/A/B/C/D）、`gradeLabel`、`gradeReason`、`gradeAuto`
- 行动：`actionStatus`、`actionText`、`actionPriority`（urgent/soon/watch/idle）
- 副状态：`silenceState`、`actionSignals`
- 响应质量：`ourResponseQuality`、`responseGapDays`、`questionUnanswered`

**（B）`data/s1_enhanced_full.json`** -- 包含与 s1_enhanced.json 相同数据的完整副本，但在 `generateDashboard()` 函数内部写入。

**（C）`output/dashboard_YYYY-MM-DD.html`** -- Apple 风格的全量工具看板，包含：6 个 KPI 卡片（总客户数 / 3天活跃 / 超90天无互动 / 未读消息 / 本期变动 / 需行动）、一个包含可点击展开弹窗的 8x5 生命周期与质量双轴矩阵、静默风险层级面板以及核心市场管道密度表。

---

## 4. 下游输出消费情况

输出结果被以下内容消费：

| 消费者 | 输入 | 用途 |
|---|---|---|
| **`scripts/gen_mobile_report.js`** | `data/s1_enhanced.json` | 筛选 `actionPriority === 'urgent' || 'soon'` 的客户，生成供微信发送的移动端 HTML/PNG 行动清单截图。这是该脚本最常见的使用方式 |
| **`scripts/gen_tracker_v2.js`** | `data/s1_enhanced.json` | 加载已增强的客户数据进行追踪相关处理 |
| **`scripts/generate_dashboard.js`** | `data/s1_enhanced_full.json` | 独立的看板生成器（似乎是旧版或替代版） |
| **`scripts/daily_pipeline.js`** | `data/s1_enhanced_full.json` | 将增强后的特征与更深层的分析数据合并 |
